import { MakeLogicType, afterMount, kea, path } from 'kea'
import { loaders } from 'kea-loaders'

import { getCurrentTeamId } from 'lib/utils/getAppContext'

import { subscriptionsList } from 'products/subscriptions/frontend/generated/api'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface subscriptionCountLogicValues {
    subscriptionCount: number | null
    subscriptionCountLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface subscriptionCountLogicActions {
    loadSubscriptionCount: () => any
    loadSubscriptionCountFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadSubscriptionCountSuccess: (
        subscriptionCount: number,
        payload?: any
    ) => {
        subscriptionCount: number
        payload?: any
    }
}

export type subscriptionCountLogicType = MakeLogicType<subscriptionCountLogicValues, subscriptionCountLogicActions>

export const subscriptionCountLogic = kea<subscriptionCountLogicType>([
    path(['lib', 'components', 'Subscriptions', 'subscriptionCountLogic']),
    loaders({
        // null = not loaded yet; consumers treat null as "unknown" and fail open.
        subscriptionCount: [
            null as number | null,
            {
                loadSubscriptionCount: async (): Promise<number> => {
                    // limit=1 keeps the payload tiny; `count` reflects the full team total.
                    const response = await subscriptionsList(String(getCurrentTeamId()), { limit: 1 })
                    return response.count ?? 0
                },
            },
        ],
    }),
    afterMount(({ actions }) => {
        actions.loadSubscriptionCount()
    }),
])
